  "inlineSchema": "// ============================================================\n// OMJEP — Schéma de base de données EA FC 26 E-Sport Platform\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// ENUMS\n// ============================================================\n\nenum UserRole {\n  ADMIN\n  MANAGER\n  PLAYER\n}\n\nenum Position {\n  GK\n  DC\n  LAT\n  RAT\n  MDC\n  MOC\n  MG\n  MD\n  BU\n  ATT\n}\n\nenum Platform {\n  CROSSPLAY\n  PS5\n  XBOX\n  PC\n}\n\nenum ClubRole {\n  FOUNDER\n  MANAGER\n  CO_MANAGER\n  PLAYER\n}\n\nenum MatchStatus {\n  SCHEDULED\n  LIVE\n  PLAYED\n  FINISHED\n  CANCELLED\n  DISPUTED\n}\n\nenum CompetitionType {\n  LEAGUE\n  CUP\n}\n\nenum CompetitionStatus {\n  DRAFT\n  ONGOING\n  FINISHED\n}\n\nenum TransferStatus {\n  PENDING\n  ACCEPTED\n  REJECTED\n}\n\nenum InvitationStatus {\n  PENDING\n  ACCEPTED\n  REJECTED\n}\n\nenum EventType {\n  GOAL\n  ASSIST\n}\n\n// ============================================================\n// MODELS\n// ============================================================\n\nmodel User {\n  id            String   @id @default(uuid()) @db.Uuid\n  email         String   @unique\n  password_hash String\n  role          UserRole @default(PLAYER)\n  created_at    DateTime @default(now())\n\n  // Identifiants de jeu\n  ea_persona_name String? @unique\n  gamertag_psn    String?\n  gamertag_xbox   String?\n\n  // Profil sportif\n  preferred_position Position?\n  nationality        String?\n\n  // Relations\n  teamMemberships     TeamMember[]\n  stats               PlayerStats?\n  transferRequests    TransferRequest[]\n  sentInvitations     Invitation[]      @relation(\"InvitationInviter\")\n  receivedInvitations Invitation[]      @relation(\"InvitationInvitee\")\n  matchEvents         MatchEvent[]\n\n  @@map(\"users\")\n}\n\nmodel Team {\n  id         String   @id @default(uuid()) @db.Uuid\n  name       String   @unique\n  logo_url   String?\n  created_at DateTime @default(now())\n\n  // Identifiants proclubs.io (crucial pour l'intégration API future)\n  ea_club_id String?  @unique\n  platform   Platform @default(CROSSPLAY)\n\n  // Relations\n  members          TeamMember[]\n  homeMatches      Match[]           @relation(\"HomeTeam\")\n  awayMatches      Match[]           @relation(\"AwayTeam\")\n  competitions     CompetitionTeam[]\n  transferRequests TransferRequest[]\n  invitations      Invitation[]\n  matchEvents      MatchEvent[]\n\n  @@map(\"teams\")\n}\n\n// Table de liaison Roster (Many-to-Many explicite User <-> Team)\nmodel TeamMember {\n  user_id   String   @db.Uuid\n  team_id   String   @db.Uuid\n  club_role ClubRole @default(PLAYER)\n  joined_at DateTime @default(now())\n\n  user User @relation(fields: [user_id], references: [id], onDelete: Cascade)\n  team Team @relation(fields: [team_id], references: [id], onDelete: Cascade)\n\n  @@id([user_id, team_id])\n  @@map(\"team_members\")\n}\n\n// Statistiques individuelles globales (One-to-One avec User)\nmodel PlayerStats {\n  id      String @id @default(uuid()) @db.Uuid\n  user_id String @unique @db.Uuid\n\n  matches_played Int   @default(0)\n  goals          Int   @default(0)\n  assists        Int   @default(0)\n  clean_sheets   Int   @default(0)\n  motm           Int   @default(0) // Man of the Match count\n  average_rating Float @default(0.0)\n\n  user User @relation(fields: [user_id], references: [id], onDelete: Cascade)\n\n  @@map(\"player_stats\")\n}\n\n// ============================================================\n// COMPÉTITIONS\n// ============================================================\n\nmodel Competition {\n  id         String            @id @default(uuid()) @db.Uuid\n  name       String            @unique\n  type       CompetitionType\n  status     CompetitionStatus @default(DRAFT)\n  start_date DateTime?\n  end_date   DateTime?\n  created_at DateTime          @default(now())\n\n  teams   CompetitionTeam[]\n  matches Match[]\n\n  @@map(\"competitions\")\n}\n\n// Table de liaison Many-to-Many Competition <-> Team\nmodel CompetitionTeam {\n  competition_id String   @db.Uuid\n  team_id        String   @db.Uuid\n  joined_at      DateTime @default(now())\n\n  competition Competition @relation(fields: [competition_id], references: [id], onDelete: Cascade)\n  team        Team        @relation(fields: [team_id], references: [id], onDelete: Cascade)\n\n  @@id([competition_id, team_id])\n  @@map(\"competition_teams\")\n}\n\nmodel Match {\n  id             String      @id @default(uuid()) @db.Uuid\n  ea_match_id    String?     @unique\n  competition_id String?     @db.Uuid\n  round          String?\n  home_team_id   String      @db.Uuid\n  away_team_id   String      @db.Uuid\n  home_score     Int?\n  away_score     Int?\n  status         MatchStatus @default(SCHEDULED)\n  played_at      DateTime?\n\n  competition Competition? @relation(fields: [competition_id], references: [id], onDelete: SetNull)\n  homeTeam    Team         @relation(\"HomeTeam\", fields: [home_team_id], references: [id])\n  awayTeam    Team         @relation(\"AwayTeam\", fields: [away_team_id], references: [id])\n  events      MatchEvent[]\n\n  @@map(\"matches\")\n}\n\nmodel MatchEvent {\n  id        String    @id @default(uuid()) @db.Uuid\n  match_id  String    @db.Uuid\n  player_id String    @db.Uuid\n  team_id   String    @db.Uuid\n  type      EventType\n  minute    Int?\n\n  match  Match @relation(fields: [match_id], references: [id], onDelete: Cascade)\n  player User  @relation(fields: [player_id], references: [id], onDelete: Cascade)\n  team   Team  @relation(fields: [team_id], references: [id], onDelete: Cascade)\n\n  @@map(\"match_events\")\n}\n\n// Mercato — demandes de transfert\nmodel TransferRequest {\n  id         String         @id @default(uuid()) @db.Uuid\n  player_id  String         @db.Uuid\n  team_id    String         @db.Uuid\n  status     TransferStatus @default(PENDING)\n  created_at DateTime       @default(now())\n\n  player User @relation(fields: [player_id], references: [id], onDelete: Cascade)\n  team   Team @relation(fields: [team_id], references: [id], onDelete: Cascade)\n\n  @@map(\"transfer_requests\")\n}\n\n// Mercato — invitations envoyées par un manager à un joueur\nmodel Invitation {\n  id            String           @id @default(uuid()) @db.Uuid\n  team_id       String           @db.Uuid\n  inviter_id    String           @db.Uuid\n  invitee_email String\n  invitee_id    String?          @db.Uuid\n  status        InvitationStatus @default(PENDING)\n  created_at    DateTime         @default(now())\n\n  team    Team  @relation(fields: [team_id], references: [id], onDelete: Cascade)\n  inviter User  @relation(\"InvitationInviter\", fields: [inviter_id], references: [id], onDelete: Cascade)\n  invitee User? @relation(\"InvitationInvitee\", fields: [invitee_id], references: [id], onDelete: SetNull)\n\n  @@map(\"invitations\")\n}\n",
